			mmCreatePanorama.t.Errorf("CatalogMock.CreatePanorama got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmCreatePanorama.CreatePanoramaMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
